#include<bits/stdc++.h>
using namespace std;
const long long mod=10007;
long long a[100010][2],b[100010][2],col[100010],x[100010],c[100010][2],cnt[100010][2];//a x b num[x] c x*num[x]
signed main()
{
	long long n,m;
	scanf("%lld%lld",&n,&m);
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld",&x[i]);
		x[i]%=mod;
	}
	long long ans=0;
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld",&col[i]);
		ans=(ans+cnt[col[i]][i%2]*i*x[i])%mod;
		ans=(ans+a[col[i]][i%2]*x[i])%mod;
		ans=(ans+b[col[i]][i%2]*i)%mod;
		ans=(ans+c[col[i]][i%2])%mod;
		cnt[col[i]][i%2]++;
		a[col[i]][i%2]+=i;
		b[col[i]][i%2]+=x[i];
		c[col[i]][i%2]+=i*x[i];
		a[col[i]][i%2]%=mod;
		b[col[i]][i%2]%=mod;
		c[col[i]][i%2]%=mod;
	}
	printf("%lld",ans%mod);
	return 0;
}
